namespace BgCommon.UI.Designer.Plugins{    /// <summary>    /// UI组件插件接口    /// </summary>    public interface IUIComponentPlugin    {        /// <summary>        /// 插件名称        /// </summary>        string Name { get; }                /// <summary>        /// 插件版本        /// </summary>        string Version { get; }                /// <summary>        /// 插件作者        /// </summary>        string Author { get; }                /// <summary>        /// 插件描述        /// </summary>        string Description { get; }                /// <summary>        /// 插件分类        /// </summary>        string Category { get; }                /// <summary>        /// 初始化插件        /// </summary>        /// <param name="context">设计上下文</param>        void Initialize(ICSharpCode.WpfDesign.DesignContext context);                /// <summary>        /// 卸载插件        /// </summary>        void Unload();                /// <summary>        /// 获取插件提供的UI组件类型        /// </summary>        /// <returns>UI组件类型列表</returns>        System.Collections.Generic.List<System.Type> GetComponentTypes();    }}